INSERT INTO facts (created_by, title, content) VALUES
(1, 'Your teeth are unique!', 'Just like fingerprints, everyone\'s teeth are completely unique! No two people in the world have exactly the same set of teeth — not even identical twins! 🦷'),
(1, 'Enamel is super strong!', 'The outer layer of your teeth called enamel is the hardest substance in your entire body — even harder than bone! But sugar and acid can still damage it, so brush well! 💪'),
(1, 'You have two sets of teeth!', 'Humans grow two sets of teeth in their lifetime. Your baby teeth (20 teeth) fall out and are replaced by 32 permanent adult teeth. Take care of them — they\'re your last set! 😮'),
(1, 'Saliva is your mouth\'s superhero!', 'Your mouth makes about 1 litre of saliva every single day! Saliva helps wash away bacteria and food, and it even contains special chemicals that help fight tooth decay. 🦸'),
(1, 'Snails have more teeth than us!', 'A garden snail can have over 14,000 tiny teeth on its tongue! Meanwhile humans only have 32. But our teeth are way more useful for chewing food! 🐌'),
(1, 'Blue toothbrushes are most popular!', 'Studies show that more people choose blue toothbrushes over any other colour. What colour is your toothbrush? 🪥'),
(1, 'Cheese is good for your teeth!', 'Eating cheese actually helps protect your teeth! It raises the pH in your mouth which reduces the risk of tooth decay. So cheese is a dentist-approved snack! 🧀'),
(1, 'Ancient people brushed too!', 'People have been cleaning their teeth for thousands of years! Ancient Egyptians used crushed eggshells and ox hooves as toothpaste. We\'re glad modern toothpaste exists! 😅');
